import './FileUploader.scss';

import type { ChangeEvent } from 'react';
import React, { forwardRef, useCallback, useEffect, useImperativeHandle, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import type { FileUploaderFile, FileUploaderProps } from './FileUploader.types';
import { FileUploaderList } from './FileUploaderList';
import { FileUploaderTitle } from './FileUploaderTitle';

export const FileUploader = forwardRef<HTMLInputElement, FileUploaderProps>(
	(
		{
			title = 'Перетащите сюда файлы или',
			dragOverTitle = 'Отпустите сюда файлы для загрузки',
			linkName = 'загрузите документы',
			subTitle,
			helperText,
			multiple = false,
			fileList,
			hideFileList = false,
			onChange,
			onRefresh,
			onRemove,
			onDrop,
			disabled = false,
			error = false,
			className,
			accept,
			sequentially = false,
			...props
		},
		ref,
	) => {
		const [files, setFiles] = useState<FileUploaderFile[]>([]);
		const [dragOver, setDragOver] = useState<boolean>(false);
		const [inputKey, setInputKey] = useState(0);
		const inputRef = useRef<HTMLInputElement>(null) as React.MutableRefObject<HTMLInputElement>;

		useImperativeHandle(ref, () => inputRef.current);

		useEffect(() => {
			const _fileList = fileList ? [...fileList] : [];
			setFiles(_fileList);
			// Не забываем обновить files в самом инпуте.
			setInputFiles(_fileList);
		}, [fileList]);

		const setInputFiles = (fileList: FileUploaderFile[]): void => {
			const inputObj = inputRef?.current;
			if (!inputObj) {
				return;
			}
			if (fileList && fileList.length > 0) {
				const dt = new DataTransfer();
				for (const file of fileList) {
					dt.items.add(new File([file], file.name));
				}
				inputObj.files = dt.files;
			} else {
				inputObj.files = null;
			}
		};

		const changeListener: EventListener = useCallback(
			(event: unknown) => {
				filesChange();
				handleDragLeave();
				onChange?.(event as ChangeEvent<HTMLInputElement>);
				setInputKey(prev => prev + 1);
			},
			[onChange],
		);

		const filesChange = (): void => {
			const inputObj = inputRef?.current;
			if (!inputObj) {
				return;
			}
			const newFiles = inputObj?.files;
			if (newFiles) {
				let newlist: FileUploaderFile[] = [];
				if (sequentially && multiple) {
					// При последовательном режиме добавляем новые файлы к существующим (только если включен multiple)
					newlist = [...files, ...Array.from(newFiles)];
				} else {
					// В обычном режиме заменяем все файлы новыми
					newlist = [...Array.from(newFiles)];
				}
				setFiles(newlist);
			}
		};

		useEffect(() => {
			const inputObj = inputRef?.current;

			if (inputObj) {
				inputObj?.addEventListener('change', changeListener);
			}

			return (): void => {
				inputObj?.removeEventListener('change', changeListener);
			};
		}, [inputKey, changeListener]); //Грязный Гарри хак: инкремент позволяет перепривязать обработчик на событие, терялась привязка, обработчик из вне по ref не срабатывал на "change"

		const handleDragOver = (): void => {
			setDragOver(true);
		};

		const handleDragLeave = (): void => {
			setDragOver(false);
		};

		const handleOnDrop = (event: React.DragEvent<HTMLInputElement>): void => {
			if (!onDrop) {
				return;
			}

			event.preventDefault();
			event.stopPropagation();

			filesChange();
			handleDragLeave();
			onDrop?.(event);
		};

		const refreshFile = (file: FileUploaderFile): void => {
			onRefresh?.(file);
		};

		const removeFile = (file: FileUploaderFile): void => {
			// Удаляем файл из состояния
			const newFiles = files.filter(f => f.name !== file.name);
			setFiles(newFiles);

			// Обновляем input.files для синхронизации
			const inputObj = inputRef?.current;
			if (inputObj) {
				const dt = new DataTransfer();
				newFiles.forEach(f => {
					dt.items.add(f);
				});
				inputObj.files = dt.files;
			}

			// Вызываем колбэк
			onRemove?.(file);
		};

		return (
			<section
				data-testid="FileUploader"
				className={classNames(
					'dsb_file-uploader-wrapper',
					disabled && 'dsb_file-uploader-wrapper__disabled',
					className,
				)}
			>
				<div
					className={classNames(
						'dsb_file-uploader',
						dragOver && 'dsb_file-uploader__drag-over',
						error && 'dsb_file-uploader__error',
					)}
				>
					<FileUploaderTitle
						title={title}
						dragOver={dragOver}
						subTitle={subTitle}
						dragOverTitle={dragOverTitle}
						linkName={linkName}
					/>

					<input
						{...props}
						disabled={disabled}
						type="file"
						multiple={multiple}
						ref={inputRef}
						onDragOver={handleDragOver}
						onDragLeave={handleDragLeave}
						onDragEnd={handleDragLeave}
						onDrop={handleOnDrop}
						className="dsb_file-uploader-input"
						accept={accept}
						aria-label={props['aria-label'] || linkName}
						aria-describedby={helperText ? 'file-uploader-helper-text' : undefined}
					/>
				</div>

				{helperText && (
					<sup id="file-uploader-helper-text" className="dsb_file-uploader-helper-text">
						{helperText}
					</sup>
				)}

				{!hideFileList && <FileUploaderList files={files} onRemove={removeFile} onRefresh={refreshFile} />}
			</section>
		);
	},
);
